CREATE TABLE digitaltwinapp.transaction_schema_i18n (
    trans_code    INTEGER     NOT NULL,
    lang          VARCHAR(10) NOT NULL,
    summary_data  TEXT        NOT NULL,
    detailed_data JSONB       NOT NULL,
    CONSTRAINT transaction_schema_i18n_pkey PRIMARY KEY (trans_code, lang),
    CONSTRAINT transaction_schema_i18n_fk   FOREIGN KEY (trans_code)
        REFERENCES digitaltwinapp.transaction_codes(code)
);

-- summary_data : single template string shown on the transaction list row.
-- detailed_data: JSON array of {"label": "...", "value": "..."} objects shown
--                on the transaction detail screen. The UI maps over this array
--                and renders each entry independently (label muted, value primary).
-- ${paths}     : resolved at runtime against the transaction_metadata JSONB
--                for that specific transaction. Language-agnostic — only the
--                surrounding text changes per locale.
--
-- Codes seeded here are those that carry meaningful extra metadata beyond what
-- the ledger already stores (amount, date, description).
-- Codes without rows fall back to displaying the raw ledger description.

-- ── P2P Sent (20026) ──────────────────────────────────────────────────────

INSERT INTO digitaltwinapp.transaction_schema_i18n VALUES (
    20026, 'en',
    'Sent ${amount} ${currency} to ${recipient_name}',
    '[{"label":"Recipient","value":"${recipient_name}"},{"label":"Email","value":"${recipient_email}"},{"label":"Amount","value":"${amount} ${currency}"}]'::jsonb
);
INSERT INTO digitaltwinapp.transaction_schema_i18n VALUES (
    20026, 'pt-BR',
    'Enviou ${amount} ${currency} para ${recipient_name}',
    '[{"label":"Destinatário","value":"${recipient_name}"},{"label":"E-mail","value":"${recipient_email}"},{"label":"Valor","value":"${amount} ${currency}"}]'::jsonb
);

-- ── P2P Received (10027) ──────────────────────────────────────────────────

INSERT INTO digitaltwinapp.transaction_schema_i18n VALUES (
    10027, 'en',
    'Received ${amount} ${currency} from ${sender_name}',
    '[{"label":"From","value":"${sender_name}"},{"label":"Email","value":"${sender_email}"},{"label":"Amount","value":"${amount} ${currency}"}]'::jsonb
);
INSERT INTO digitaltwinapp.transaction_schema_i18n VALUES (
    10027, 'pt-BR',
    'Recebeu ${amount} ${currency} de ${sender_name}',
    '[{"label":"De","value":"${sender_name}"},{"label":"E-mail","value":"${sender_email}"},{"label":"Valor","value":"${amount} ${currency}"}]'::jsonb
);

-- ── Buy: fiat debit side (50005) ──────────────────────────────────────────
-- Shown on the fiat wallet (e.g. USD): "you paid X USD for Y USDC"

INSERT INTO digitaltwinapp.transaction_schema_i18n VALUES (
    50005, 'en',
    'Purchased ${to_amount} ${to_currency} for ${from_amount} ${from_currency}',
    '[{"label":"Paid","value":"${from_amount} ${from_currency}"},{"label":"Received","value":"${to_amount} ${to_currency}"},{"label":"Rate","value":"1 ${to_currency} = ${rate} ${from_currency}"}]'::jsonb
);
INSERT INTO digitaltwinapp.transaction_schema_i18n VALUES (
    50005, 'pt-BR',
    'Comprou ${to_amount} ${to_currency} por ${from_amount} ${from_currency}',
    '[{"label":"Pago","value":"${from_amount} ${from_currency}"},{"label":"Recebido","value":"${to_amount} ${to_currency}"},{"label":"Taxa","value":"1 ${to_currency} = ${rate} ${from_currency}"}]'::jsonb
);

